SELECT vessel_name, created_at
FROM gps_data
WHERE ground_speed_knots = (SELECT MAX(ground_speed_knots) FROM gps_data);

SELECT vessel_name
FROM gps_data
WHERE ground_speed_knots = (
  SELECT MAX(ground_speed_knots) FROM gps_data
)
LIMIT 1;

SELECT vessel_name
FROM gps_data
WHERE ground_speed_knots = (
  SELECT MAX(ground_speed_knots) FROM gps_data
);

SELECT user_id
FROM users
ORDER BY user_id;

SELECT DISTINCT data_source
FROM gps_data
ORDER BY data_source ASC;

SELECT v.vessel_name
FROM vessels v
JOIN gps_data g ON v.vessel_id = g.vessel_id
WHERE g.created_at = (
    SELECT MAX(created_at) FROM gps_data
);
